func (m Model) renderBanner() string {
    tabs := []struct {
        id    ViewID
        label string
        key   string
    }{
        {ViewClaude, "Claude", "1"},
        {ViewAgents, "Agents", "2"},
        {ViewStats, "Stats", "3"},
