func (m *PanelModel) updateViewport() {
    var b strings.Builder

    for _, msg := range m.messages {
        switch msg.Role {
        case "user":
            b.WriteString(userStyle.Render("You: "))
            b.WriteString(msg.Content)
        case "assistant":
            b.WriteString(assistantStyle.Render("Claude: "))
