    hookHeaderStyle  = lipgloss.NewStyle().Bold(true)
    hookSuccessStyle = lipgloss.NewStyle().Foreground(lipgloss.Color("green"))
    hookFailStyle    = lipgloss.NewStyle().Foreground(lipgloss.Color("red"))
)
