)

type ViewID int

const (
    ViewClaude ViewID = iota
    ViewAgents
    ViewStats
    ViewQuery
)

type Model struct {
    width       int
    height      int
    ready       bool
    activeView  ViewID
    showHelp    bool

    // Session filter
    sessionFilter string // "current", "today", "week", "all"

    // Sub-components (will be added in later tickets)
    // claudePanel  claude.Model
    // agentTree    agents.Model
    // statsPanel   stats.Model
}

func New() Model {
    return Model{
        activeView:    ViewClaude,
        sessionFilter: "current",
    }
}

func (m Model) Init() tea.Cmd {
    return nil
}

func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
    switch msg := msg.(type) {
    case tea.WindowSizeMsg:
        m.width = msg.Width
        m.height = msg.Height
        m.ready = true
        return m, nil

    case tea.KeyMsg:
        return m.handleKey(msg)
    }

    return m, nil
}

func (m Model) handleKey(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
    // Global keys
    switch msg.String() {
    case "ctrl+c", "q":
        return m, tea.Quit
    case "?":
        m.showHelp = !m.showHelp
        return m, nil
    case "1":
        m.activeView = ViewClaude
    case "2":
        m.activeView = ViewAgents
    case "3":
        m.activeView = ViewStats
    case "4":
        m.activeView = ViewQuery
    case "tab":
        m.activeView = (m.activeView + 1) % 4
    case "shift+tab":
        m.activeView = (m.activeView + 3) % 4
    }

    return m, nil
}

func (m Model) View() string {
    if !m.ready {
        return "Initializing..."
    }

    if m.showHelp {
        return m.renderHelp()
    }

    return lipgloss.JoinVertical(
        lipgloss.Left,
        m.renderBanner(),
        m.renderContent(),
        m.renderStatusBar(),
    )
}
