### 2. Implement Update Handler

```go
func (m TreeModel) Update(msg tea.Msg) (TreeModel, tea.Cmd) {
    if !m.focused {
        return m, nil
    }

    switch msg := msg.(type) {
    case tea.KeyMsg:
        switch msg.String() {
        case "up", "k":
            if m.cursor > 0 {
                m.cursor--
            }
        case "down", "j":
            agents := m.tree.GetAll()
            if m.cursor < len(agents)-1 {
                m.cursor++
            }
        case "enter", "space":
            agents := m.tree.GetAll()
            if m.cursor < len(agents) {
                id := agents[m.cursor].ID
                m.expanded[id] = !m.expanded[id]
            }
        }
    }

    return m, nil
}
```

