    viewport  viewport.Model
    textarea  textarea.Model
    messages  []Message
    hooks     []HookEvent
    cost      float64
    sessionID string
    width     int
    height    int
    focused   bool
    streaming bool
}

type Message struct {
    Role    string // "user" or "assistant"
    Content string
}

type HookEvent struct {
    Name    string
    Success bool
}

func NewPanelModel(process *cli.ClaudeProcess) PanelModel {
    ta := textarea.New()
    ta.Placeholder = "Type your message here..."
    ta.Focus()
    ta.CharLimit = 4096
    ta.SetWidth(80)
    ta.SetHeight(1)

    vp := viewport.New(80, 20)

    return PanelModel{
        process:   process,
        viewport:  vp,
        textarea:  ta,
        messages:  make([]Message, 0),
        hooks:     make([]HookEvent, 0),
        sessionID: process.SessionID(),
    }
}
