func (m *PanelModel) appendStreamingText(text string) {
    if len(m.messages) > 0 && m.messages[len(m.messages)-1].Role == "assistant" {
        m.messages[len(m.messages)-1].Content += text
    } else {
        m.messages = append(m.messages, Message{
            Role:    "assistant",
            Content: text,
        })
    }
    m.updateViewport()
}

