	// Write malformed JSONL
	dir := filepath.Dir(globalPath)
	os.MkdirAll(dir, 0755)
	content := `{"collaboration_id":"valid","timestamp":123,"session_id":"test"}
not-json-data
{"collaboration_id":"valid2","timestamp":456,"session_id":"test2"}

{"incomplete":
