## Sharp Edges

### Common Gotchas

1. **Loop variable capture in goroutines**
   ```go
   // WRONG: All goroutines see same value
   for _, item := range items {
       go func() {
           process(item)  // BUG: item changes
       }()
   }

   // CORRECT: Capture variable
   for _, item := range items {
       item := item  // Capture
       go func() {
           process(item)
       }()
   }
   ```

2. **Nil slice vs empty slice**
   ```go
   var s []int        // nil slice, json: null
   s := []int{}       // empty slice, json: []
   s := make([]int,0) // empty slice, json: []
   ```

3. **defer in loops**
   ```go
   // WRONG: Defers accumulate until function returns
   for _, file := range files {
       f, _ := os.Open(file)
       defer f.Close()  // Won't close until function ends
   }

   // CORRECT: Use anonymous function
   for _, file := range files {
       func() {
           f, _ := os.Open(file)
           defer f.Close()
           // ... use f ...
       }()
   }
   ```

4. **Channel closing**
   ```go
   // Only sender should close channels
   // Never close from receiver side
   // Closing twice causes panic
   ```

5. **Context cancellation**
   ```go
   // Always check context in long-running operations
   select {
   case <-ctx.Done():
       return ctx.Err()
   default:
   }
   ```

package session

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"

	"github.com/Bucket-Chemist/GOgent-Fortress/pkg/config"
)

// CollectSessionMetrics gathers statistics from session logs and temp files.
// Returns SessionMetrics with counts from tool counters, error log, and violations log.
// Missing files are not errors - returns 0 for those metrics.
func CollectSessionMetrics(sessionID string) (*SessionMetrics, error) {
	metrics := &SessionMetrics{
		SessionID: sessionID,
	}

	// Count tool calls from temp counters
	toolCount, err := countToolCalls()
	if err == nil {
		metrics.ToolCalls = toolCount
	}

	// Count errors from error log
	errorCount, err := countLogLines(getErrorLogPath())
	if err == nil {
		metrics.ErrorsLogged = errorCount
	}

	// Count routing violations
	violationCount, err := countLogLines(config.GetViolationsLogPath())
	if err == nil {
		metrics.RoutingViolations = violationCount
	}

	return metrics, nil
}

// countToolCalls reads the tool counter from the XDG-compliant counter file.
// The counter is atomically incremented by gogent-sharp-edge on each PostToolUse event.
// Returns 0 if the counter file doesn't exist (normal for first session).
func countToolCalls() (int, error) {
	return config.GetToolCount()
}

// countLogLines counts all lines in a file, matching bash wc -l behavior.
// Returns 0 if file doesn't exist (not an error).
// Counts ALL lines including empty lines to match bash hook implementation.
func countLogLines(path string) (int, error) {
	file, err := os.Open(path)
	if err != nil {
		if os.IsNotExist(err) {
			return 0, nil // Missing file is normal
		}
		return 0, fmt.Errorf("failed to open %s: %w", path, err)
	}
	defer file.Close()

	count := 0
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		count++
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading %s: %w", path, err)
	}

	return count, nil
}

// getErrorLogPath returns the path to the error patterns log.
// Uses XDG-compliant location from config package.
func getErrorLogPath() string {
	return filepath.Join(config.GetGOgentDir(), "claude-error-patterns.jsonl")
}

